import { APIGateway } from "encore.dev/api";

const service = new APIGateway("user");

export interface UserResponse {
  id: number;
  name: string;
}

service.get("/user/:id", async (ctx): Promise<UserResponse> => {
  const id = parseInt(ctx.pathParams.id);
  if (id === 1) {
    return { id, name: "Alice" };
  }
  return { id, name: "Unknown" };
});

export default service;

