# Defining type-safe TypeScript APIs with Encore.ts
created: undefined, last updated: 2026-04-27, [Read more](https://encore.dev/docs/ts/primitives/defining-apis)

To define an API endpoint, use the `api` function from the `encore.dev/api` module.
This function wraps a regular TypeScript async function, designating it as an API endpoint.
...
In the example below, we define the API endpoint `ping` which accepts `POST` requests and is exposed as `hello.ping` (because our service name is `hello`).
...
// inside the hello.ts file
import { api } from "encore.dev/api";
export const ping = api(
{ method: "POST" },
async (p: PingParams): Promise<PingResponse> => {
return { message: `Hello ${p.name}!` };
},
);
...
import { api } from "encore.dev/api";
// PingParams is the request data for the Ping endpoint.
interface PingParams {
name: string;
}
...
message: string;
}
// hello is an API endpoint that responds with a simple response.
export const hello = api(
{ method: "POST", path: "/hello" },
async (p: PingParams): Promise<PingResponse> => {
return { message: `Hello ${p.name}!` };
},
);

# Start your app & Explore Local...
